#include <stdio.h>
#include <stdlib.h>

typedef struct node {
    int data;
    struct node *next;
} node_t;

void insert_end(node_t **head, int value) {
    node_t *new_node = malloc(sizeof(node_t));
    new_node->data = value;
    new_node->next = NULL;

    if (*head == NULL) {
        *head = new_node;
        return;
    }

    node_t *curr = *head;
    while (curr->next) curr = curr->next;
    curr->next = new_node;
}

/* YOUR CODE HERE */


