    node_t *list = NULL;
    insert_end(&list, 1);
    insert_end(&list, 1);
    insert_end(&list, 2);
    insert_end(&list, 3);
    insert_end(&list, 3);
    insert_end(&list, 3);
    insert_end(&list, 4);

    remove_duplicates(&list);
    print_list(list);  // Should print: 1 2 3 4
    return 0;
}

